function parseBody(input) {
  let body = input;
  if (body && body.type === 'Buffer' && Array.isArray(body.data)) {
    try { body = Buffer.from(body.data).toString('utf8'); } catch (e) {}
  }
  if (typeof body === 'string') {
    try { body = JSON.parse(body); }
    catch (e) {
      try {
        const probe = JSON.parse(`{"${body}":""}`);
        const keys = Object.keys(probe);
        if (keys.length === 1 && /^[\[{]/.test(keys[0])) body = JSON.parse(keys[0]);
      } catch (e2) {}
    }
  }
  if (typeof body === 'object' && body && !Array.isArray(body)) {
    const keys = Object.keys(body);
    if (keys.length === 1 && /^[\[{]/.test(keys[0])) {
      try { body = JSON.parse(keys[0]); } catch (e3) {}
    }
  }
  return body;
}

function normalizeToGroupArray(input) {
  if (Array.isArray(input)) return input;
  if (input && Array.isArray(input.timed)) return [input];
  if (input && input.data && Array.isArray(input.data)) return input.data;
  if (input && input.data && Array.isArray(input.data.plans)) return input.data.plans;
  if (input && Array.isArray(input.plans)) return input.plans;
  return [];
}

function numericValue(value) {
  const raw = value && typeof value === 'object' && 'value' in value ? value.value : value;
  const n = Number(String(raw ?? '').replace(/[^0-9+-.]/g, '').trim());
  return Number.isFinite(n) ? n : undefined;
}

function normalizeConstraints(input) {
  const c = input || {};
  const minSoc = numericValue(c.min_soc) ?? 0;
  const maxSoc = numericValue(c.max_soc) ?? 100;
  const maxCharge = numericValue(c.max_charge_power) ?? 100;
  const maxDischarge = numericValue(c.max_discharge_power) ?? 100;
  return {
    ...c,
    min_soc: { value: Math.max(0, Math.min(100, minSoc)), unit: '%' },
    max_soc: { value: Math.max(0, Math.min(100, maxSoc)), unit: '%' },
    max_charge_power: { value: Math.max(0, Math.min(100, maxCharge)), unit: '%' },
    max_discharge_power: { value: Math.max(0, Math.min(100, maxDischarge)), unit: '%' }
  };
}

function validateAndSanitizeGroups(groupsIn) {
  const supportedPv = new Set(['SelfConsumption', 'GridSupplement', 'Off', 'GridSell', 'ReserveBattery', 'NoChange']);
  const errors = [];
  const warnings = [];
  const groups = JSON.parse(JSON.stringify(groupsIn || []));

  for (let gi = 0; gi < groups.length; gi += 1) {
    const group = groups[gi];
    if (!group || typeof group !== 'object') {
      errors.push(`group[${gi}] is not an object`);
      continue;
    }
    if (!Array.isArray(group.timed)) {
      errors.push(`group[${gi}].timed missing/invalid`);
      group.timed = [];
    }
    for (let pi = 0; pi < group.timed.length; pi += 1) {
      const plan = group.timed[pi] || {};
      const path = `group[${gi}].timed[${pi}]`;
      if (!plan.planID) errors.push(`${path}: missing planID`);

      if (plan.time && (plan.time.start || plan.time.end)) {
        const start = new Date(plan.time.start);
        const end = new Date(plan.time.end);
        if (isNaN(start.getTime())) errors.push(`${path}.time.start invalid`);
        if (isNaN(end.getTime())) errors.push(`${path}.time.end invalid`);
        if (!isNaN(start.getTime()) && !isNaN(end.getTime()) && end <= start) errors.push(`${path}: time.end <= time.start`);
      } else {
        if (!plan.cron || String(plan.cron).trim().split(/\s+/).length !== 5) errors.push(`${path}.cron must have 5 fields`);
        const duration = Number(plan?.duration?.value ?? plan.duration);
        if (!Number.isFinite(duration) || duration < 1) errors.push(`${path}.duration.value must be minutes >= 1`);
        else plan.duration = { unit: 'minutes', value: Math.trunc(duration) };
      }

      if (plan.start && isNaN(new Date(plan.start).getTime())) errors.push(`${path}.start invalid`);
      if (plan.until && isNaN(new Date(plan.until).getTime())) errors.push(`${path}.until invalid`);

      plan.constraints = normalizeConstraints(plan.constraints);
      if (numericValue(plan.constraints.min_soc) >= numericValue(plan.constraints.max_soc)) {
        errors.push(`${path}: constraints.min_soc >= max_soc`);
      }

      const strategy = plan.strategy || {};
      if (!strategy.meter_rule && !strategy.pv_rule && plan.activePowerKwSetpoint == null && plan.setpoint?.activePowerKw == null) {
        errors.push(`${path}: strategy or active setpoint is required`);
      }
      if (strategy.pv_rule) {
        const name = String(strategy.pv_rule.name || '').trim();
        if (!name) errors.push(`${path}: pv_rule.name missing`);
        else if (!supportedPv.has(name)) errors.push(`${path}: pv_rule.name '${name}' not supported`);
      }
      for (const side of ['charge', 'discharge']) {
        const branch = strategy.meter_rule && strategy.meter_rule[side];
        if (!branch) continue;
        const keys = ['net_load_threshold', 'net_load_threshold_percent', 'fixed_output'].filter((key) => branch[key] != null);
        if (keys.length > 1) errors.push(`${path}: meter_rule.${side} mixes control types`);
        if (branch.net_load_threshold) branch.net_load_threshold = { unit: 'kW', value: numericValue(branch.net_load_threshold) };
        if (branch.fixed_output) branch.fixed_output = { unit: branch.fixed_output.unit || '%', value: numericValue(branch.fixed_output) };
      }
      plan.strategy = strategy;
      plan.default = plan.default === true || String(plan.default).toLowerCase() === 'true';
    }
  }

  return { ok: errors.length === 0, errors, warnings, groupsSanitized: groups };
}

function flattenPlans(groups) {
  const flat = [];
  for (const group of groups || []) {
    for (const plan of Array.isArray(group?.timed) ? group.timed : []) {
      const meter = plan?.strategy?.meter_rule || {};
      const charge = meter.charge || {};
      const discharge = meter.discharge || {};
      let type = 'Unknown';
      if (discharge.fixed_output) type = 'Discharge';
      else if (charge.fixed_output) type = 'Charge';
      else if (discharge.net_load_threshold) type = 'DischargeThreshold';
      else if (charge.net_load_threshold) type = 'ChargeThreshold';
      flat.push({
        planID: plan.planID || 'unknown',
        name: plan.name || 'Unnamed',
        description: plan.description || '',
        default: !!plan.default,
        runState: plan.runState || 'Idle',
        duration: Number(plan?.duration?.value ?? plan.duration ?? 0) || 0,
        start: plan.start || '',
        until: plan.until || '',
        time: plan.time || undefined,
        cron: plan.cron || '',
        type,
        fixed_output: discharge.fixed_output || charge.fixed_output || undefined,
        net_load_threshold: { charge: charge.net_load_threshold, discharge: discharge.net_load_threshold },
        net_load_threshold_percent: { charge: charge.net_load_threshold_percent, discharge: discharge.net_load_threshold_percent },
        min_soc: plan?.constraints?.min_soc,
        max_soc: plan?.constraints?.max_soc,
        max_charge_power: plan?.constraints?.max_charge_power,
        max_discharge_power: plan?.constraints?.max_discharge_power,
        constraints: plan.constraints || {},
        strategy: plan.strategy || {},
        activePowerKwSetpoint: plan.activePowerKwSetpoint,
        setpoint: plan.setpoint,
        exclude_holidays: plan.exclude_holidays || null
      });
    }
  }
  return flat;
}

function publishPlans(groups) {
  flow.set('plans', groups);
  global.set('schedulePlans', groups);
  global.set('scheduleRaw', groups);
  global.set('scheduleUpdatedAt', new Date().toISOString());
  const config = global.get('controlConfig') || global.get('unifiedControlConfig');
  if (config && config.operation) {
    config.operation.scheduledControlEnabled = true;
    global.set('controlConfig', config);
    global.set('unifiedControlConfig', config);
  }
}

function storedControlConfig() {
  return global.get('controlConfig') || global.get('unifiedControlConfig') || flow.get('controlConfig') || null;
}

function saveControlConfig(config) {
  global.set('controlConfig', config);
  global.set('unifiedControlConfig', config);
  flow.set('controlConfig', config);
}

const payload = parseBody(msg.payload) || {};
const method = payload.method || payload?.data?.method || payload?.action || '';
const response = {
  code: 0,
  message: 'Success',
  version: payload.version || '1.0',
  requestId: payload.requestId || 0,
  timestamp: Math.floor(Date.now() / 1000),
  data: { code: 0, message: 'Success' }
};

let plans = flow.get('plans') || global.get('schedulePlans') || [];

switch (method) {
  case 'GetControlConfig':
    response.data = { config: storedControlConfig() };
    break;
  case 'SaveControlConfig':
    if (!payload?.data?.config) {
      response.code = -5;
      response.message = 'Missing config';
      response.data = { code: -5, message: 'Missing config' };
      break;
    }
    saveControlConfig(payload.data.config);
    response.data = { code: 0, message: 'OK' };
    break;
  case 'Append': {
    const groups = normalizeToGroupArray(payload.data !== undefined ? payload.data : payload);
    const valid = validateAndSanitizeGroups(groups);
    if (!groups.length || !valid.ok) {
      response.code = -4;
      response.message = !groups.length ? 'No timed groups to append' : 'Validation failed';
      response.data = { code: response.code, message: response.message, errors: valid.errors, warnings: valid.warnings };
      break;
    }
    const incomingHasDefault = valid.groupsSanitized.some((group) => (group.timed || []).some((plan) => plan.default));
    if (incomingHasDefault) {
      plans = plans.map((group) => ({ ...group, timed: (group.timed || []).filter((plan) => !plan.default) })).filter((group) => group.timed.length);
    }
    plans = plans.concat(valid.groupsSanitized);
    publishPlans(plans);
    response.data = { code: 0, message: 'Appended', count: valid.groupsSanitized.length, warnings: valid.warnings };
    break;
  }
  case 'GetList':
    response.data = { code: 0, message: 'Success', plans: flattenPlans(plans), devices: [] };
    break;
  case 'Reset':
    plans = [];
    publishPlans(plans);
    response.data = { code: 0, message: 'Reset', count: 0 };
    break;
  case 'Delete': {
    const planID = payload?.data?.planID || payload.planID;
    if (!planID) {
      response.code = -3;
      response.message = 'Missing planID';
      response.data = { code: -3, message: 'Missing planID' };
      break;
    }
    plans = plans.map((group) => ({ ...group, timed: (group.timed || []).filter((plan) => plan.planID !== planID) })).filter((group) => group.timed.length);
    publishPlans(plans);
    response.data = { code: 0, message: 'Deleted', planID };
    break;
  }
  default: {
    const groups = normalizeToGroupArray(payload);
    const valid = validateAndSanitizeGroups(groups);
    if (!groups.length || !valid.ok) {
      response.code = -1;
      response.message = !groups.length ? 'Unknown method or empty payload' : 'Validation failed';
      response.data = { code: response.code, message: response.message, errors: valid.errors, warnings: valid.warnings };
      break;
    }
    plans = valid.groupsSanitized;
    publishPlans(plans);
    response.data = { code: 0, message: 'Saved', count: plans.length, warnings: valid.warnings };
  }
}

msg.payload = response;
return msg;

const telemetry = global.get('telemetry') || global.get('Telemetry') || global.get('latestTelemetry') || {};
const now = new Date();
const t = now.getTime() / 1000;

function readTag(tag) {
  if (!tag) return undefined;
  const direct = telemetry[tag];
  if (typeof direct === 'number') return direct;
  if (direct && typeof direct.value === 'number') return direct.value;
  const parts = tag.split('.');
  let current = telemetry;
  for (const part of parts) {
    if (!current || typeof current !== 'object') return undefined;
    current = current[part];
  }
  if (typeof current === 'number') return current;
  if (current && typeof current.value === 'number') return current.value;
  return undefined;
}

function numberOrFallback(value, fallback) {
  return typeof value === 'number' && Number.isFinite(value) ? value : fallback;
}

const utilityRaw = readTag('Meter.Utility_Total_Power') ?? readTag('Meter.POI_kW');
const pvRaw = readTag('Meter2.Solar') ?? readTag('PCS.DcPv_kW') ?? readTag('Meter.PV_Total_Power');
const pcsRaw = readTag('PCS.SYSTEM_POWER_ACTIVE_ALL') ?? readTag('PCS.ACBusTotalActivePower');
const generatorRaw = readTag('Meter.Generator_Total_Power');
const hasTelemetry = [utilityRaw, pvRaw, pcsRaw, generatorRaw].some((value) => typeof value === 'number');
const utilityPowerKw = numberOrFallback(utilityRaw, Math.round((35 + Math.sin(t / 9) * 12) * 10) / 10);
const pvKw = numberOrFallback(pvRaw, Math.round(Math.max(0, 18 + Math.sin(t / 7) * 18) * 10) / 10);
const pcsActivePowerKw = numberOrFallback(pcsRaw, Math.round(Math.sin(t / 5) * 22 * 10) / 10);
const siteLoadKw = Math.round((utilityPowerKw + pvKw + pcsActivePowerKw) * 10) / 10;
const generatorRunning = numberOrFallback(generatorRaw, 0) > 1;

msg.headers = { 'content-type': 'application/json' };
msg.payload = {
  data: {
    signals: { utilityPowerKw, pvKw, pcsActivePowerKw, siteLoadKw, generatorRunning },
    raw: {
      'Meter.Utility_Total_Power': utilityRaw,
      'Meter2.Solar': pvRaw,
      'PCS.SYSTEM_POWER_ACTIVE_ALL': pcsRaw,
      'Meter.Generator_Total_Power': generatorRaw
    },
    source: hasTelemetry ? 'node-red-global-telemetry' : 'node-red-test-waveform',
    updatedAt: now.toISOString()
  }
};
return msg;
